// ============================================================
// components/ProtectedRoute.jsx — Route Guard Component
// ============================================================
// Wraps private routes to prevent unauthenticated access.
// If the user is not logged in, they're redirected to /login.
// If a specific role is required and doesn't match, redirected
// to the appropriate home page.
//
// Usage in AppRoutes.jsx:
//   <ProtectedRoute role="merchant">
//     <MerchantDashboard />
//   </ProtectedRoute>
// ============================================================

import React from "react";
import { Navigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

function ProtectedRoute({ children, role }) {
  const { isAuthenticated, role: userRole } = useAuth();

  // Not logged in at all → go to login
  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  // Wrong role (e.g., merchant trying to access admin panel)
  if (role && userRole !== role) {
    return <Navigate to={userRole === "admin" ? "/admin/dashboard" : "/dashboard"} replace />;
  }

  // All checks passed — render the protected page
  return children;
}

export default ProtectedRoute;
